import { useEffect, useState } from "react";

import {
  LineChart,
  Line,
  XAxis,
  YAxis,
 Tooltip,
  CartesianGrid,
  ResponsiveContainer
} from "recharts";

function App() {

  const [homes, setHomes] = useState([]);
  const [trades, setTrades] = useState([]);
  const [chartData, setChartData] = useState([]);
  const [predictions, setPredictions] = useState([]);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {

    const fetchEnergy = () => {

      fetch("http://localhost:5000/energy")
        .then((res) => res.json())
        .then((data) => {

          setHomes(data.homes || []);
          setTrades(data.trades || []);
          setPredictions(data.predictions || []);
          setAlerts(data.alerts || []);

          const totalGenerated =
            data.homes.reduce(
              (sum, home) => sum + home.generatedPower,
              0
            );

          const totalConsumed =
            data.homes.reduce(
              (sum, home) => sum + home.consumedPower,
              0
            );

          setChartData((prev) => [

            ...prev.slice(-9),

            {
              time: new Date().toLocaleTimeString(),
              generated: totalGenerated,
              consumed: totalConsumed
            }

          ]);

        });

    };

    fetchEnergy();

    const interval = setInterval(fetchEnergy, 3000);

    return () => clearInterval(interval);

  }, []);

  // SYSTEM ANALYTICS

  const totalHomes = homes.length;

  const activeSellers =
    homes.filter(
      (home) => home.status === "SELLING ENERGY"
    ).length;

  const activeBuyers =
    homes.filter(
      (home) => home.status === "BUYING ENERGY"
    ).length;

  return (

    <div className="min-h-screen bg-black text-white p-8">

      {/* TITLE */}

      <h1 className="text-5xl font-bold text-green-400 mb-10 text-center">
        OpenGreenGrid Dashboard
      </h1>

      {/* OVERVIEW CARDS */}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">

        <div className="bg-gray-900 border border-cyan-400 rounded-2xl p-6 text-center shadow-lg">
          <h2 className="text-2xl font-bold text-cyan-300">
            Total Homes
          </h2>

          <p className="text-5xl font-bold mt-4">
            {totalHomes}
          </p>
        </div>

        <div className="bg-gray-900 border border-green-400 rounded-2xl p-6 text-center shadow-lg">
          <h2 className="text-2xl font-bold text-green-300">
            Energy Sellers
          </h2>

          <p className="text-5xl font-bold mt-4">
            {activeSellers}
          </p>
        </div>

        <div className="bg-gray-900 border border-red-400 rounded-2xl p-6 text-center shadow-lg">
          <h2 className="text-2xl font-bold text-red-300">
            Energy Buyers
          </h2>

          <p className="text-5xl font-bold mt-4">
            {activeBuyers}
          </p>
        </div>

      </div>

      {/* SMART HOMES */}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {homes.map((home, index) => (

          <div
            key={index}
            className="bg-gray-900 border border-green-500 rounded-2xl p-6 shadow-lg hover:scale-105 transition duration-300"
          >

            <h2 className="text-3xl font-semibold mb-4 text-green-300">
              {home.house}
            </h2>

            <p className="text-lg mb-2">
              ⚡ Generated Power:
              <span className="text-green-400 font-bold">
                {" "} {home.generatedPower} kWh
              </span>
            </p>

            <p className="text-lg mb-2">
              🔋 Consumed Power:
              <span className="text-yellow-400 font-bold">
                {" "} {home.consumedPower} kWh
              </span>
            </p>

            <p className="text-lg mb-2">
              🔌 Battery Level:
              <span className="text-blue-400 font-bold">
                {" "} {home.batteryLevel}%
              </span>
            </p>

            <p className="text-lg mb-2">
              🌱 Carbon Saved:
              <span className="text-emerald-400 font-bold">
                {" "} {home.carbonSaved} kg
              </span>
            </p>

            <p className="text-lg mb-4">
              🤖 Efficiency Score:
              <span className="text-pink-400 font-bold">
                {" "} {home.efficiencyScore}%
              </span>
            </p>

            {/* AI STATUS */}

            <div
              className={`p-3 rounded-xl text-center font-bold text-lg
              ${
                home.status === "SELLING ENERGY"
                  ? "bg-green-600"
                  : home.status === "BUYING ENERGY"
                  ? "bg-red-600"
                  : "bg-yellow-500 text-black"
              }`}
            >

              {home.status}

            </div>

          </div>

        ))}

      </div>

      {/* TRADING SECTION */}

      <div className="mt-12">

        <h2 className="text-4xl font-bold text-cyan-400 mb-6">
          Autonomous Energy Trades
        </h2>

        {trades.length === 0 ? (

          <div className="bg-gray-900 p-4 rounded-xl text-gray-400">
            No active trades currently
          </div>

        ) : (

          trades.map((trade, index) => (

            <div
              key={index}
              className="bg-cyan-900 border border-cyan-400 p-5 rounded-xl mb-4 shadow-lg"
            >

              <p className="text-xl">

                ⚡ <span className="font-bold">
                  {trade.from}
                </span>

                {" "} sold {" "}

                <span className="text-cyan-300 font-bold">
                  {trade.energy} kWh
                </span>

                {" "} to {" "}

                <span className="font-bold">
                  {trade.to}
                </span>

              </p>

            </div>

          ))

        )}

      </div>

      {/* REAL-TIME ENERGY CHART */}

      <div className="mt-12">

        <h2 className="text-4xl font-bold text-purple-400 mb-6">
          Real-Time Energy Analytics
        </h2>

        <div className="bg-gray-900 p-6 rounded-2xl border border-purple-500">

          <ResponsiveContainer width="100%" height={400}>

            <LineChart data={chartData}>

              <CartesianGrid strokeDasharray="3 3" />

              <XAxis dataKey="time" />

              <YAxis />

              <Tooltip />

              <Line
                type="monotone"
                dataKey="generated"
                stroke="#00ff88"
                strokeWidth={3}
              />

              <Line
                type="monotone"
                dataKey="consumed"
                stroke="#ff4444"
                strokeWidth={3}
              />

            </LineChart>

          </ResponsiveContainer>

        </div>

      </div>

      {/* GRID HEALTH SYSTEM */}

      <div className="mt-12">

        <h2 className="text-4xl font-bold text-blue-400 mb-6">
          Smart Grid Health
        </h2>

        <div className="bg-gray-900 border border-blue-500 rounded-2xl p-8 shadow-lg">

          <p className="text-2xl mb-4">
            ⚡ Total Generated Energy:
            <span className="text-green-400 font-bold">
              {" "}
              {
                chartData.length > 0
                  ? chartData[chartData.length - 1].generated.toFixed(2)
                  : 0
              } kWh
            </span>
          </p>

          <p className="text-2xl mb-4">
            🔋 Total Consumed Energy:
            <span className="text-yellow-400 font-bold">
              {" "}
              {
                chartData.length > 0
                  ? chartData[chartData.length - 1].consumed.toFixed(2)
                  : 0
              } kWh
            </span>
          </p>

          <p className="text-2xl">
            🤖 Grid Status:
            <span className="text-cyan-400 font-bold">
              {" "}
              {
                chartData.length > 0 &&
                chartData[chartData.length - 1].generated >
                chartData[chartData.length - 1].consumed
                  ? "GRID OPERATING EFFICIENTLY"
                  : "HIGH GRID LOAD DETECTED"
              }
            </span>
          </p>

        </div>

      </div>

      {/* AI PREDICTION ENGINE */}

      <div className="mt-12">

        <h2 className="text-4xl font-bold text-orange-400 mb-6">
          AI Prediction Engine
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          {predictions.map((item, index) => (

            <div
              key={index}
              className="bg-gray-900 border border-orange-500 rounded-2xl p-6 shadow-lg"
            >

              <h3 className="text-2xl font-bold text-orange-300 mb-4">
                {item.house}
              </h3>

              <p className="text-lg font-semibold">
                {item.prediction}
              </p>

            </div>

          ))}

        </div>

      </div>

      {/* SMART ALERT SYSTEM */}

      <div className="mt-12">

        <h2 className="text-4xl font-bold text-red-400 mb-6">
          Smart Grid Alerts
        </h2>

        {alerts.length === 0 ? (

          <div className="bg-gray-900 p-5 rounded-xl text-gray-400">
            No critical alerts detected
          </div>

        ) : (

          alerts.map((alert, index) => (

            <div
              key={index}
              className="bg-red-900 border border-red-500 p-5 rounded-xl mb-4 shadow-lg animate-pulse"
            >

              <p className="text-xl font-bold">
                🚨 {alert.house}
              </p>

              <p className="text-lg mt-2">
                {alert.message}
              </p>

            </div>

          ))

        )}

      </div>

    </div>

  );

}

export default App;
